const input = $json;

const systemPrompt = `# Rol
Eres el Activities Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Convertir el roadmap y el veredicto en un backlog ejecutable orientado a Kanban y Gantt.

# Instrucciones
- Genera actividades concretas, no abstractas.
- Cada actividad debe tener épica, prioridad, owner_role, duración estimada, dependencia y phase_id.
- Las actividades deben ser útiles para ejecución real.
- Usa estados kanban iniciales apropiados.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "activities": [
    {
      "activity_id": "A1",
      "epic": "",
      "title": "",
      "description": "",
      "priority": "alta",
      "owner_role": "",
      "estimated_days": 0,
      "depends_on": [],
      "kanban_status": "todo",
      "phase_id": "P1"
    }
  ]
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    activities: {
      type: "array",
      items: {
        type: "object",
        properties: {
          activity_id: { type: "string" },
          epic: { type: "string" },
          title: { type: "string" },
          description: { type: "string" },
          priority: { type: "string" },
          owner_role: { type: "string" },
          estimated_days: { type: "number" },
          depends_on: { type: "array", items: { type: "string" } },
          kanban_status: { type: "string" },
          phase_id: { type: "string" }
        },
        required: ["activity_id", "epic", "title", "description", "priority", "owner_role", "estimated_days", "depends_on", "kanban_status", "phase_id"]
      }
    }
  },
  required: ["activities"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.activities = Array.isArray(content.activities) ? content.activities : [];
content.activities = content.activities.map((a, idx) => ({
  activity_id: a?.activity_id || `A${idx + 1}`,
  epic: a?.epic || "",
  title: a?.title || `Actividad ${idx + 1}`,
  description: a?.description || "",
  priority: a?.priority || "media",
  owner_role: a?.owner_role || "",
  estimated_days: Number(a?.estimated_days || 0),
  depends_on: Array.isArray(a?.depends_on) ? a.depends_on : [],
  kanban_status: a?.kanban_status || "todo",
  phase_id: a?.phase_id || ""
}));

return [{ json: content }];

const data = $json;

if (!Array.isArray(data.activities)) {
  throw new Error('activities faltante o inválido');
}

return [{ json: data }];
